local tabs = MemoryPool.newTable()

TabsConfig = {}

function TabsConfig:loadConfig()

    local temp = FileUtil.getConfigFromCsv("setting/ShopTab.csv", 3)


    for _, Value in pairs(temp) do
        tabs[tonumber(Value.n_Id)] = {
            Id = tonumber(Value.n_Id),
            Type = tonumber(Value.n_Type),
            Icon = Value.s_Icon,
            Name = Value.s_Name
        }

    end
    --print("--------------------------------")
    --print(json.encode(tabs))
end

function TabsConfig:getTabs()
    return tabs
end


function TabsConfig:getTabsById(Id)

    return tabs[Id]
end